// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *ThingsReaderMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *ThingsReaderMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockAddTaskDone() &&
		m.MinimockSetTaskCanceledDone() &&
		m.MinimockSetTaskCompletedDone() &&
		m.MinimockTagsDone() &&
		m.MinimockTasksByTagPageDone() &&
		m.MinimockTasksInListDone() &&
		m.MinimockTasksInListPageDone()
}
